Production SAML implementations need to handle multi-IDP scenarios securely while implementing robust replay protection and monitoring.

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, redirect, session, abort, g
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from functools import wraps
import redis
import hashlib
import time
import os
import logging
import json
from datetime import datetime, timedelta
from typing import Dict, Optional

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY')

# Production logging with audit trail
logger = logging.getLogger('saml_auth')
logger.setLevel(logging.INFO)
handler = logging.StreamHandler()
handler.setFormatter(logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
))
logger.addHandler(handler)

# Redis for assertion replay protection
redis_client = redis.Redis(
    host=os.environ.get('REDIS_HOST', 'localhost'),
    port=int(os.environ.get('REDIS_PORT', 6379)),
    password=os.environ.get('REDIS_PASSWORD'),
    ssl=os.environ.get('REDIS_SSL', 'true').lower() == 'true',
    decode_responses=True
)

class SAMLAssertionReplayProtection:
    """Prevents replay attacks by tracking used assertion IDs."""

    ASSERTION_TTL = 3600  # 1 hour - matches typical SAML assertion validity

    def __init__(self, redis_client: redis.Redis):
        self.redis = redis_client

    def is_assertion_replayed(self, assertion_id: str, issuer: str) -> bool:
        """Check if assertion ID has been used before."""
        key = f"saml:assertion:{issuer}:{hashlib.sha256(assertion_id.encode()).hexdigest()}"

        # Atomic check-and-set to prevent race conditions
        result = self.redis.set(
            key, 
            str(int(time.time())), 
            nx=True,  # Only set if not exists
            ex=self.ASSERTION_TTL
        )

        # If result is None, key already existed (replay detected)
        return result is None

    def record_assertion(self, assertion_id: str, issuer: str, 
                         not_on_or_after: datetime) -> None:
        """Record assertion with appropriate TTL based on validity period."""
        key = f"saml:assertion:{issuer}:{hashlib.sha256(assertion_id.encode()).hexdigest()}"

        # Calculate TTL from assertion's NotOnOrAfter
        ttl = int((not_on_or_after - datetime.utcnow()).total_seconds())
        ttl = max(ttl, 300)  # Minimum 5 minutes
        ttl = min(ttl, self.ASSERTION_TTL)  # Maximum 1 hour

        self.redis.setex(key, ttl, str(int(time.time())))

class MultiIDPSAMLManager:
    """Manages multiple identity providers securely."""

    def __init__(self):
        self.idp_configs = self._load_idp_configs()
        self.replay_protection = SAMLAssertionReplayProtection(redis_client)

    def _load_idp_configs(self) -> Dict:
        """Load IDP configurations from secure storage."""
        # In production, load from secure config service or HSM
        configs = {}
        idp_list = json.loads(os.environ.get('SAML_IDP_LIST', '[]'))

        for idp_id in idp_list:
            configs[idp_id] = {
                'strict': True,
                'debug': False,
                'sp': {
                    'entityId': os.environ.get('SAML_SP_ENTITY_ID'),
                    'assertionConsumerService': {
                        'url': os.environ.get('SAML_ACS_URL'),
                        'binding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST'
                    },
                    'x509cert': os.environ.get('SAML_SP_CERT'),
                    'privateKey': os.environ.get('SAML_SP_KEY')
                },
                'idp': {
                    'entityId': os.environ.get(f'SAML_IDP_{idp_id}_ENTITY_ID'),
                    'singleSignOnService': {
                        'url': os.environ.get(f'SAML_IDP_{idp_id}_SSO_URL'),
                        'binding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect'
                    },
                    'x509cert': os.environ.get(f'SAML_IDP_{idp_id}_CERT')
                },
                'security': {
                    'wantAssertionsSigned': True,
                    'wantMessagesSigned': True,
                    'wantAssertionsEncrypted': True,
                    'rejectUnsolicitedResponsesWithInResponseTo': True,
                    'requestedAuthnContext': ['urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport'],
                    'signatureAlgorithm': 'http://www.w3.org/2001/04/xmldsig-more#rsa-sha256',
                    'digestAlgorithm': 'http://www.w3.org/2001/04/xmlenc#sha256',
                    'lowercaseUrlencoding': True
                }
            }
        return configs

    def get_auth(self, idp_id: str, request_data: Dict) -> Optional[OneLogin_Saml2_Auth]:
        """Get SAML auth instance for specific IDP."""
        if idp_id not in self.idp_configs:
            logger.warning(f"Unknown IDP requested: {idp_id}")
            return None

        return OneLogin_Saml2_Auth(request_data, self.idp_configs[idp_id])

    def validate_and_process(self, idp_id: str, request_data: Dict) -> Dict:
        """Validate SAML response with comprehensive security checks."""
        auth = self.get_auth(idp_id, request_data)
        if not auth:
            raise ValueError(f"Invalid IDP: {idp_id}")

        # Process with full validation
        auth.process_response()

        errors = auth.get_errors()
        if errors:
            raise SecurityError(f"SAML validation failed: {errors}")

        if not auth.is_authenticated():
            raise SecurityError("SAML assertion not authenticated")

        # Extract assertion ID for replay protection
        last_assertion_id = auth.get_last_assertion_id()
        last_assertion_issuer = auth.get_last_assertion_issuer()

        if not last_assertion_id:
            raise SecurityError("Missing assertion ID")

        # CRITICAL: Check for replay attack
        if self.replay_protection.is_assertion_replayed(
            last_assertion_id, 
            last_assertion_issuer
        ):
            logger.critical(
                f"SAML REPLAY ATTACK DETECTED! "
                f"Assertion ID: {last_assertion_id}, "
                f"Issuer: {last_assertion_issuer}"
            )
            raise SecurityError("Assertion replay detected")

        return {
            'name_id': auth.get_nameid(),
            'session_index': auth.get_session_index(),
            'attributes': auth.get_attributes(),
            'issuer': last_assertion_issuer,
            'assertion_id': last_assertion_id
        }

class SecurityError(Exception):
    """Custom exception for security-related errors."""
    pass

# Initialize SAML manager
saml_manager = MultiIDPSAMLManager()

def audit_log(event_type: str, details: Dict) -> None:
    """Send audit events to SIEM."""
    audit_entry = {
        'timestamp': datetime.utcnow().isoformat(),
        'event_type': event_type,
        'source_ip': request.remote_addr,
        'user_agent': request.headers.get('User-Agent'),
        **details
    }
    logger.info(f"AUDIT: {json.dumps(audit_entry)}")

def rate_limit(max_attempts: int = 10, window_seconds: int = 60):
    """Rate limiting decorator for SSO endpoints."""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            key = f"rate_limit:saml:{request.remote_addr}"
            current = redis_client.get(key)

            if current and int(current) >= max_attempts:
                audit_log('RATE_LIMIT_EXCEEDED', {
                    'endpoint': request.path
                })
                abort(429, description='Too many authentication attempts')

            redis_client.incr(key)
            redis_client.expire(key, window_seconds)

            return f(*args, **kwargs)
        return wrapped
    return decorator

@app.route('/saml/login/<idp_id>')
def saml_login(idp_id: str):
    """Initiate SAML authentication with specified IDP."""
    req = prepare_flask_request(request)
    auth = saml_manager.get_auth(idp_id, req)

    if not auth:
        abort(400, description='Invalid identity provider')

    # Store relay state for post-auth redirect
    relay_state = request.args.get('next', '/dashboard')

    # Validate relay state to prevent open redirect
    if not relay_state.startswith('/'):
        relay_state = '/dashboard'

    session['saml_relay_state'] = relay_state
    session['saml_idp_id'] = idp_id

    audit_log('SAML_LOGIN_INITIATED', {'idp': idp_id})

    return redirect(auth.login())

@app.route('/saml/acs', methods=['POST'])
@rate_limit(max_attempts=10, window_seconds=60)
def saml_acs():
    """SAML Assertion Consumer Service with full security."""
    idp_id = session.get('saml_idp_id')

    if not idp_id:
        audit_log('SAML_NO_IDP_SESSION', {})
        abort(400, description='No SSO session found')

    req = prepare_flask_request(request)

    try:
        user_data = saml_manager.validate_and_process(idp_id, req)

        # Create secure session
        session.regenerate()  # Prevent session fixation
        session['user'] = user_data['name_id']
        session['saml_session_index'] = user_data['session_index']
        session['idp'] = user_data['issuer']
        session['authenticated'] = True
        session['auth_time'] = datetime.utcnow().isoformat()
        session['attributes'] = user_data['attributes']

        audit_log('SAML_LOGIN_SUCCESS', {
            'user': user_data['name_id'],
            'idp': user_data['issuer']
        })

        relay_state = session.pop('saml_relay_state', '/dashboard')
        return redirect(relay_state)

    except SecurityError as e:
        audit_log('SAML_SECURITY_ERROR', {
            'error': str(e),
            'idp': idp_id
        })
        abort(401, description='Authentication failed')
    except Exception as e:
        logger.error(f"SAML processing error: {e}")
        audit_log('SAML_PROCESSING_ERROR', {
            'error': str(e),
            'idp': idp_id
        })
        abort(500, description='Internal server error')

@app.route('/saml/slo', methods=['GET', 'POST'])
def saml_single_logout():
    """Handle SAML Single Logout."""
    idp_id = session.get('saml_idp_id')
    if not idp_id:
        return redirect('/login')

    req = prepare_flask_request(request)
    auth = saml_manager.get_auth(idp_id, req)

    if not auth:
        session.clear()
        return redirect('/login')

    # Process logout request/response
    url = auth.process_slo(delete_session_cb=lambda: session.clear())

    audit_log('SAML_LOGOUT', {
        'user': session.get('user'),
        'idp': idp_id
    })

    if url:
        return redirect(url)

    return redirect('/login')

def prepare_flask_request(request):
    """Prepare Flask request for SAML processing."""
    return {
        'https': 'on' if request.scheme == 'https' else 'off',
        'http_host': request.host,
        'script_name': request.path,
        'get_data': request.args.copy(),
        'post_data': request.form.copy()
    }

# Production security headers
@app.after_request
def add_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Content-Security-Policy'] = "default-src 'self'"
    return response

if __name__ == '__main__':
    # Production: Use gunicorn with TLS
    app.run(host='0.0.0.0', port=5000, debug=False)
```

**Defense in Depth Layers**:

1. **Cryptographic Signature Verification**: All SAML assertions must be signed with RSA-SHA256 and verified against the IDP's trusted certificate
```python
'security': {
    'wantAssertionsSigned': True,
    'wantMessagesSigned': True,
    'signatureAlgorithm': 'http://www.w3.org/2001/04/xmldsig-more#rsa-sha256'
}
```

2. **Assertion Replay Protection**: Redis-backed tracking of assertion IDs prevents reuse
```python
def is_assertion_replayed(self, assertion_id: str, issuer: str) -> bool:
    key = f"saml:assertion:{issuer}:{hashlib.sha256(assertion_id.encode()).hexdigest()}"
    result = self.redis.set(key, str(int(time.time())), nx=True, ex=self.ASSERTION_TTL)
    return result is None  # True if already existed (replay)
```

3. **Rate Limiting**: Prevents brute-force attacks on SSO endpoints
```python
@rate_limit(max_attempts=10, window_seconds=60)
def saml_acs():
    # Rate limited to 10 attempts per minute per IP
```

**Additional Protections**:
- **Session Fixation Prevention**: `session.regenerate()` after authentication
- **Open Redirect Prevention**: Relay state validation ensures redirects stay within application
- **Comprehensive Audit Logging**: All authentication events logged with IP, user agent, and outcome
- **Strict IDP Validation**: Multi-IDP support with per-IDP certificate validation
- **Security Headers**: HSTS, CSP, X-Frame-Options to prevent additional attack vectors
- **Encrypted Assertions**: `wantAssertionsEncrypted: True` protects assertion contents in transit

Your check-then-act pattern creates a classic Time-of-Check to Time-of-Use (TOCTOU) race condition. An attacker can send multiple simultaneous registration requests that all pass the uniqueness check before any account is created, resulting in duplicate accounts.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

const UserSchema = new mongoose.Schema({
  username: String,
  email: String,
  password: String,
  createdAt: { type: Date, default: Date.now }
});

const User = mongoose.model('User', UserSchema);

// VULNERABLE: Race condition in registration
app.post('/api/register', async (req, res) => {
  const { username, email, password } = req.body;

  try {
    // CHECK: Is username/email available?
    const existingUser = await User.findOne({
      $or: [{ username }, { email }]
    });

    if (existingUser) {
      return res.status(409).json({ error: 'Username or email already exists' });
    }

    // RACE WINDOW: Time gap between check and create
    // Another request can pass the check during this window

    const hashedPassword = await bcrypt.hash(password, 10);

    // ACT: Create user
    const newUser = new User({
      username,
      email,
      password: hashedPassword
    });

    await newUser.save();

    res.status(201).json({ message: 'User created', userId: newUser._id });
  } catch (error) {
    res.status(500).json({ error: 'Registration failed' });
  }
});

app.listen(3000);
```

**Attack Script**:
```javascript
// Attacker sends 50 concurrent registration requests
const axios = require('axios');

async function exploitRaceCondition() {
  const payload = {
    username: 'admin',
    email: 'admin@company.com',
    password: 'attacker123'
  };

  // Send 50 simultaneous requests
  const requests = Array(50).fill().map(() => 
    axios.post('http://target.com/api/register', payload)
      .catch(e => e.response)
  );

  const results = await Promise.all(requests);
  const successes = results.filter(r => r.status === 201);
  console.log(`Created ${successes.length} duplicate accounts!`);
}

exploitRaceCondition();
```

**Why This Is Dangerous**:
- Multiple requests pass the `findOne` check simultaneously before any user is created
- `bcrypt.hash()` takes ~100ms, widening the race window significantly
- No database-level constraints prevent duplicate entries
- Attackers can claim privileged usernames like 'admin' or impersonate real users

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const mongoose = require('mongoose');
const { body, validationResult } = require('express-validator');

const app = express();
app.use(express.json());

// DEFENSE 1: Database-level unique constraints
const UserSchema = new mongoose.Schema({
  username: { 
    type: String, 
    required: true,
    unique: true,  // Creates unique index
    lowercase: true,
    trim: true
  },
  email: { 
    type: String, 
    required: true,
    unique: true,  // Creates unique index
    lowercase: true,
    trim: true
  },
  password: { type: String, required: true },
  createdAt: { type: Date, default: Date.now }
});

// Ensure indexes are created
UserSchema.index({ username: 1 }, { unique: true });
UserSchema.index({ email: 1 }, { unique: true });

const User = mongoose.model('User', UserSchema);

// SECURE: Rely on database constraints, handle duplicate key errors
app.post('/api/register',
  // DEFENSE 2: Input validation
  body('username').isLength({ min: 3, max: 30 }).matches(/^[a-zA-Z0-9_]+$/),
  body('email').isEmail().normalizeEmail(),
  body('password').isLength({ min: 8 }),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { username, email, password } = req.body;

    try {
      const hashedPassword = await bcrypt.hash(password, 12);

      // DEFENSE 3: Atomic insert - let database handle uniqueness
      const newUser = new User({
        username: username.toLowerCase(),
        email: email.toLowerCase(),
        password: hashedPassword
      });

      await newUser.save();

      console.log(`[AUDIT] User registered: ${username} from ${req.ip}`);
      res.status(201).json({ message: 'User created', userId: newUser._id });

    } catch (error) {
      // DEFENSE 4: Handle duplicate key error gracefully
      if (error.code === 11000) {
        const field = Object.keys(error.keyPattern)[0];
        console.log(`[SECURITY] Duplicate registration attempt: ${field}`);
        return res.status(409).json({ 
          error: `${field} already exists` 
        });
      }

      console.error('[ERROR] Registration failed:', error.message);
      res.status(500).json({ error: 'Registration failed' });
    }
  }
);

app.listen(3000);
```

**Key Security Controls**:
- **Database unique constraints**: MongoDB's unique index is atomic and prevents duplicates regardless of timing
- **Atomic insert pattern**: Skip the check, let the database reject duplicates via error code 11000
- **Input validation**: Normalize and validate before processing
- **Graceful error handling**: Convert database constraint violations to user-friendly messages

Excellent questions! In distributed systems, database constraints alone may not be sufficient due to replication lag. For multi-step registration flows, you need distributed locking and reservation patterns.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const mongoose = require('mongoose');
const Redis = require('ioredis');
const Redlock = require('redlock');
const { body, validationResult } = require('express-validator');
const rateLimit = require('express-rate-limit');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Redis for distributed locking
const redis = new Redis(process.env.REDIS_URL);
const redlock = new Redlock([redis], {
  retryCount: 3,
  retryDelay: 200
});

// DEFENSE 1: Rate limiting per IP
const registrationLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 registration attempts per window
  message: { error: 'Too many registration attempts' },
  standardHeaders: true,
  legacyHeaders: false
});

// Schema with unique constraints
const UserSchema = new mongoose.Schema({
  username: { type: String, required: true, unique: true, lowercase: true },
  email: { type: String, required: true, unique: true, lowercase: true },
  password: { type: String, required: true },
  status: { type: String, enum: ['pending', 'active', 'suspended'], default: 'pending' },
  emailVerified: { type: Boolean, default: false },
  createdAt: { type: Date, default: Date.now }
});

// Reservation schema for multi-step registration
const ReservationSchema = new mongoose.Schema({
  username: { type: String, required: true, unique: true, lowercase: true },
  email: { type: String, required: true, unique: true, lowercase: true },
  token: { type: String, required: true, unique: true },
  expiresAt: { type: Date, required: true, index: { expireAfterSeconds: 0 } },
  createdAt: { type: Date, default: Date.now }
});

const User = mongoose.model('User', UserSchema);
const Reservation = mongoose.model('Reservation', ReservationSchema);

// STEP 1: Reserve username/email with distributed lock
app.post('/api/register/start',
  registrationLimiter,
  body('username').isLength({ min: 3, max: 30 }).matches(/^[a-zA-Z0-9_]+$/),
  body('email').isEmail().normalizeEmail(),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { username, email } = req.body;
    const normalizedUsername = username.toLowerCase();
    const normalizedEmail = email.toLowerCase();

    // DEFENSE 2: Distributed lock prevents race conditions across nodes
    const lockKey = `registration:${normalizedUsername}:${normalizedEmail}`;
    let lock;

    try {
      // Acquire distributed lock (10 second TTL)
      lock = await redlock.acquire([lockKey], 10000);

      // Check if username/email already exists in Users
      const existingUser = await User.findOne({
        $or: [
          { username: normalizedUsername },
          { email: normalizedEmail }
        ]
      }).read('primary'); // DEFENSE 3: Read from primary to avoid replication lag

      if (existingUser) {
        return res.status(409).json({ error: 'Username or email already taken' });
      }

      // Check existing reservations
      const existingReservation = await Reservation.findOne({
        $or: [
          { username: normalizedUsername },
          { email: normalizedEmail }
        ]
      }).read('primary');

      if (existingReservation) {
        return res.status(409).json({ error: 'Username or email already reserved' });
      }

      // Create reservation with 15-minute TTL
      const reservationToken = crypto.randomBytes(32).toString('hex');
      const reservation = new Reservation({
        username: normalizedUsername,
        email: normalizedEmail,
        token: reservationToken,
        expiresAt: new Date(Date.now() + 15 * 60 * 1000) // 15 minutes
      });

      await reservation.save();

      console.log(`[AUDIT] Registration started: ${normalizedUsername} from ${req.ip}`);

      // Return token for step 2
      res.status(200).json({
        message: 'Username reserved. Complete registration within 15 minutes.',
        reservationToken,
        expiresIn: 900 // seconds
      });

    } catch (error) {
      if (error.code === 11000) {
        return res.status(409).json({ error: 'Username or email already taken' });
      }

      console.error('[ERROR] Registration start failed:', error.message);
      res.status(500).json({ error: 'Registration failed' });

    } finally {
      // DEFENSE 4: Always release lock
      if (lock) {
        await lock.release().catch(err => 
          console.error('[ERROR] Lock release failed:', err)
        );
      }
    }
  }
);

// STEP 2: Complete registration with reserved token
app.post('/api/register/complete',
  registrationLimiter,
  body('reservationToken').isHexadecimal().isLength({ min: 64, max: 64 }),
  body('password').isLength({ min: 8 }).matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { reservationToken, password } = req.body;

    // DEFENSE 5: Use MongoDB transaction for atomicity
    const session = await mongoose.startSession();
    session.startTransaction();

    try {
      // Find and delete reservation atomically
      const reservation = await Reservation.findOneAndDelete(
        { token: reservationToken },
        { session }
      );

      if (!reservation) {
        await session.abortTransaction();
        return res.status(400).json({ error: 'Invalid or expired reservation' });
      }

      // Hash password
      const hashedPassword = await bcrypt.hash(password, 12);

      // Create user within transaction
      const newUser = new User({
        username: reservation.username,
        email: reservation.email,
        password: hashedPassword,
        status: 'pending'
      });

      await newUser.save({ session });

      // Commit transaction
      await session.commitTransaction();

      // DEFENSE 6: Audit logging
      console.log(`[AUDIT] User created: ${newUser.username} (${newUser._id}) from ${req.ip}`);

      // Send verification email (async, don't block response)
      sendVerificationEmail(newUser.email, newUser._id).catch(err =>
        console.error('[ERROR] Verification email failed:', err)
      );

      res.status(201).json({
        message: 'Registration complete. Please verify your email.',
        userId: newUser._id
      });

    } catch (error) {
      await session.abortTransaction();

      if (error.code === 11000) {
        console.log(`[SECURITY] Race condition caught by DB constraint`);
        return res.status(409).json({ error: 'Username or email already exists' });
      }

      console.error('[ERROR] Registration complete failed:', error.message);
      res.status(500).json({ error: 'Registration failed' });

    } finally {
      session.endSession();
    }
  }
);

// DEFENSE 7: Cleanup expired reservations (backup to TTL index)
async function cleanupExpiredReservations() {
  try {
    const result = await Reservation.deleteMany({
      expiresAt: { $lt: new Date() }
    });
    if (result.deletedCount > 0) {
      console.log(`[CLEANUP] Removed ${result.deletedCount} expired reservations`);
    }
  } catch (error) {
    console.error('[ERROR] Cleanup failed:', error.message);
  }
}

// Run cleanup every 5 minutes
setInterval(cleanupExpiredReservations, 5 * 60 * 1000);

async function sendVerificationEmail(email, userId) {
  // Implementation for email verification
}

app.listen(3000);
```

