**SECURE VERSION**:

```java
import org.opensaml.saml2.core.*;
import org.opensaml.xml.signature.*;
import org.opensaml.xml.security.x509.*;
import org.opensaml.xml.validation.*;
import org.w3c.dom.*;
import javax.xml.parsers.*;
import java.security.cert.*;
import java.time.*;
import javax.servlet.http.*;
import java.io.*;
import org.slf4j.*;

public class SecureSAMLHandler extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureSAMLHandler.class);
    private static final String EXPECTED_AUDIENCE = "https://myapp.company.com";
    private static final String EXPECTED_ISSUER = "https://idp.company.com";
    private static final int CLOCK_SKEW_SECONDS = 300;

    private X509Certificate idpCertificate;

    @Override
    public void init() {
        // Load IdP certificate from secure configuration
        this.idpCertificate = loadIdPCertificate();
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String clientIP = request.getRemoteAddr();

        try {
            String samlResponse = request.getParameter("SAMLResponse");
            if (samlResponse == null || samlResponse.isEmpty()) {
                logger.warn("Empty SAML response from IP: {}", clientIP);
                response.sendError(400, "Invalid request");
                return;
            }

            byte[] decodedResponse = java.util.Base64.getDecoder().decode(samlResponse);

            // SECURE: XXE-protected XML parsing
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);
            factory.setNamespaceAware(true);

            DocumentBuilder builder = factory.newDocumentBuilder();
            Document doc = builder.parse(new ByteArrayInputStream(decodedResponse));

            Response samlResp = parseSAMLResponse(doc);

            // SECURE: Validate signature with known IdP certificate
            if (!validateSignature(samlResp, idpCertificate)) {
                logger.error("Invalid SAML signature from IP: {}", clientIP);
                response.sendError(401, "Authentication failed");
                return;
            }

            Assertion assertion = samlResp.getAssertions().get(0);

            // SECURE: Validate issuer
            if (!EXPECTED_ISSUER.equals(assertion.getIssuer().getValue())) {
                logger.error("Invalid issuer from IP: {}", clientIP);
                response.sendError(401, "Authentication failed");
                return;
            }

            // SECURE: Validate audience restriction
            if (!validateAudience(assertion)) {
                logger.error("Invalid audience from IP: {}", clientIP);
                response.sendError(401, "Authentication failed");
                return;
            }

            // SECURE: Validate time conditions
            if (!validateTimeConditions(assertion)) {
                logger.error("Expired/invalid assertion time from IP: {}", clientIP);
                response.sendError(401, "Authentication failed");
                return;
            }

            String nameId = assertion.getSubject().getNameID().getValue();
            logger.info("Successful SSO authentication for user: {} from IP: {}", nameId, clientIP);

            HttpSession session = request.getSession(true);
            session.setAttribute("user", nameId);
            session.setAttribute("authTime", Instant.now().toString());
            response.sendRedirect("/dashboard");

        } catch (Exception e) {
            logger.error("SAML processing error from IP: {}", clientIP, e);
            response.sendError(401, "Authentication failed");
        }
    }

    private boolean validateAudience(Assertion assertion) {
        Conditions conditions = assertion.getConditions();
        for (AudienceRestriction restriction : conditions.getAudienceRestrictions()) {
            for (Audience audience : restriction.getAudiences()) {
                if (EXPECTED_AUDIENCE.equals(audience.getAudienceURI())) {
                    return true;
                }
            }
        }
        return false;
    }

    private boolean validateTimeConditions(Assertion assertion) {
        Instant now = Instant.now();
        Conditions conditions = assertion.getConditions();

        Instant notBefore = conditions.getNotBefore().toInstant()
            .minusSeconds(CLOCK_SKEW_SECONDS);
        Instant notOnOrAfter = conditions.getNotOnOrAfter().toInstant()
            .plusSeconds(CLOCK_SKEW_SECONDS);

        return now.isAfter(notBefore) && now.isBefore(notOnOrAfter);
    }
}
```

**Key Security Controls**:
- **XXE Prevention**: Disabled DOCTYPE declarations, external entities, and XInclude to prevent XML-based attacks
- **Signature Validation**: Cryptographically verifies the SAML response against the known IdP certificate
- **Audience Restriction**: Ensures the assertion was intended for this specific service provider
- **Time Validation**: Checks NotBefore and NotOnOrAfter conditions with configurable clock skew tolerance
- **Issuer Validation**: Confirms the assertion came from the expected Identity Provider

Excellent question. Production SAML implementations must handle multiple Identity Providers, prevent replay attacks, and implement comprehensive monitoring. The 2023 Zimbra SAML implementation flaw (CVE-2023-37580) showed how improper replay protection led to widespread account takeover.

**PRODUCTION PATTERN**:

```java
import org.opensaml.saml2.core.*;
import org.opensaml.xml.signature.*;
import org.opensaml.security.SAMLSignatureProfileValidator;
import java.security.cert.*;
import java.time.*;
import java.util.*;
import java.util.concurrent.*;
import javax.servlet.http.*;
import org.slf4j.*;
import io.micrometer.core.instrument.*;

public class ProductionSAMLService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionSAMLService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    // IdP configuration registry
    private final Map<String, IdPConfiguration> idpRegistry = new ConcurrentHashMap<>();

    // Replay attack prevention: assertion ID cache with TTL
    private final Cache<String, Instant> usedAssertionIds;

    // Metrics
    private final Counter successfulAuthCounter;
    private final Counter failedAuthCounter;
    private final Counter replayAttemptCounter;
    private final Timer authProcessingTimer;

    public ProductionSAMLService(MeterRegistry meterRegistry) {
        // Initialize assertion cache with TTL matching max assertion validity
        this.usedAssertionIds = Caffeine.newBuilder()
            .expireAfterWrite(Duration.ofHours(24))
            .maximumSize(1_000_000)
            .build();

        // Initialize metrics
        this.successfulAuthCounter = meterRegistry.counter("saml.auth.success");
        this.failedAuthCounter = meterRegistry.counter("saml.auth.failure");
        this.replayAttemptCounter = meterRegistry.counter("saml.replay.attempt");
        this.authProcessingTimer = meterRegistry.timer("saml.auth.processing.time");

        // Load IdP configurations from secure storage
        loadIdPConfigurations();
    }

    public AuthenticationResult processSSO(HttpServletRequest request) {
        Timer.Sample sample = Timer.start();
        String clientIP = getClientIP(request);
        String requestId = UUID.randomUUID().toString();

        try {
            logger.debug("Processing SAML request, requestId={}, clientIP={}", requestId, clientIP);

            // Rate limiting check
            if (isRateLimited(clientIP)) {
                logger.warn("Rate limit exceeded, requestId={}, clientIP={}", requestId, clientIP);
                failedAuthCounter.increment();
                return AuthenticationResult.rateLimited();
            }

            String samlResponse = request.getParameter("SAMLResponse");
            String relayState = request.getParameter("RelayState");

            // Input validation
            ValidationResult validationResult = validateInput(samlResponse, relayState);
            if (!validationResult.isValid()) {
                logger.warn("Invalid input, requestId={}, reason={}", requestId, validationResult.getReason());
                failedAuthCounter.increment();
                return AuthenticationResult.invalidRequest(validationResult.getReason());
            }

            // Parse SAML response with XXE protection
            Response response = parseSecurely(samlResponse);

            // Identify IdP from issuer
            String issuerId = response.getIssuer().getValue();
            IdPConfiguration idpConfig = idpRegistry.get(issuerId);

            if (idpConfig == null) {
                auditLogger.warn("Unknown IdP attempted authentication, " +
                    "requestId={}, issuerId={}, clientIP={}", requestId, issuerId, clientIP);
                failedAuthCounter.increment();
                return AuthenticationResult.unknownIdP();
            }

            // Comprehensive validation
            SAMLValidationContext context = SAMLValidationContext.builder()
                .requestId(requestId)
                .clientIP(clientIP)
                .idpConfig(idpConfig)
                .response(response)
                .build();

            // 1. Validate XML signature
            SignatureValidationResult sigResult = validateSignature(context);
            if (!sigResult.isValid()) {
                auditLogger.error("Signature validation failed, " +
                    "requestId={}, idp={}, reason={}, clientIP={}",
                    requestId, issuerId, sigResult.getReason(), clientIP);
                failedAuthCounter.increment();
                return AuthenticationResult.signatureFailed();
            }

            Assertion assertion = response.getAssertions().get(0);

            // 2. Check for replay attack
            String assertionId = assertion.getID();
            if (isReplayedAssertion(assertionId)) {
                auditLogger.error("REPLAY ATTACK DETECTED, " +
                    "requestId={}, assertionId={}, idp={}, clientIP={}",
                    requestId, assertionId, issuerId, clientIP);
                replayAttemptCounter.increment();
                failedAuthCounter.increment();

                // Alert security team
                triggerSecurityAlert("SAML_REPLAY_ATTACK", Map.of(
                    "assertionId", assertionId,
                    "clientIP", clientIP,
                    "idp", issuerId
                ));

                return AuthenticationResult.replayDetected();
            }

            // 3. Validate assertion conditions
            ConditionsValidationResult condResult = validateConditions(assertion, idpConfig);
            if (!condResult.isValid()) {
                auditLogger.warn("Conditions validation failed, " +
                    "requestId={}, reason={}, clientIP={}",
                    requestId, condResult.getReason(), clientIP);
                failedAuthCounter.increment();
                return AuthenticationResult.conditionsFailed(condResult.getReason());
            }

            // 4. Validate subject confirmation
            SubjectConfirmationResult subjectResult = validateSubjectConfirmation(
                assertion, request);
            if (!subjectResult.isValid()) {
                auditLogger.warn("Subject confirmation failed, " +
                    "requestId={}, reason={}, clientIP={}",
                    requestId, subjectResult.getReason(), clientIP);
                failedAuthCounter.increment();
                return AuthenticationResult.subjectConfirmationFailed();
            }

            // 5. Extract user identity
            UserIdentity identity = extractUserIdentity(assertion, idpConfig);

            // 6. Record assertion as used (replay prevention)
            markAssertionUsed(assertionId);

            // Success - audit log
            auditLogger.info("SSO authentication successful, " +
                "requestId={}, user={}, idp={}, clientIP={}, sessionIndex={}",
                requestId, identity.getUserId(), issuerId, clientIP,
                assertion.getAuthnStatements().get(0).getSessionIndex());

            successfulAuthCounter.increment();

            return AuthenticationResult.success(identity, relayState);

        } catch (SAMLProcessingException e) {
            logger.error("SAML processing error, requestId={}, clientIP={}",
                requestId, clientIP, e);
            failedAuthCounter.increment();
            return AuthenticationResult.processingError();
        } finally {
            sample.stop(authProcessingTimer);
        }
    }

    private boolean isReplayedAssertion(String assertionId) {
        Instant existing = usedAssertionIds.getIfPresent(assertionId);
        return existing != null;
    }

    private void markAssertionUsed(String assertionId) {
        usedAssertionIds.put(assertionId, Instant.now());
    }

    private SignatureValidationResult validateSignature(
            SAMLValidationContext context) {
        try {
            Response response = context.getResponse();
            IdPConfiguration idpConfig = context.getIdpConfig();

            // Validate response signature if present
            if (response.getSignature() != null) {
                SAMLSignatureProfileValidator profileValidator = 
                    new SAMLSignatureProfileValidator();
                profileValidator.validate(response.getSignature());

                SignatureValidator sigValidator = new SignatureValidator(
                    idpConfig.getSigningCredential());
                sigValidator.validate(response.getSignature());
            }

            // Validate assertion signature (REQUIRED)
            Assertion assertion = response.getAssertions().get(0);
            if (assertion.getSignature() == null) {
                return SignatureValidationResult.failed("Assertion must be signed");
            }

            SAMLSignatureProfileValidator profileValidator = 
                new SAMLSignatureProfileValidator();
            profileValidator.validate(assertion.getSignature());

            SignatureValidator sigValidator = new SignatureValidator(
                idpConfig.getSigningCredential());
            sigValidator.validate(assertion.getSignature());

            // Verify certificate is not revoked
            if (idpConfig.isOCSPEnabled()) {
                if (!checkCertificateRevocation(idpConfig.getSigningCertificate())) {
                    return SignatureValidationResult.failed("Certificate revoked");
                }
            }

            return SignatureValidationResult.valid();

        } catch (ValidationException e) {
            return SignatureValidationResult.failed(e.getMessage());
        }
    }

    private ConditionsValidationResult validateConditions(
            Assertion assertion, IdPConfiguration idpConfig) {
        Conditions conditions = assertion.getConditions();
        Instant now = Instant.now();
        int clockSkew = idpConfig.getAllowedClockSkewSeconds();

        // Validate NotBefore
        if (conditions.getNotBefore() != null) {
            Instant notBefore = conditions.getNotBefore().toInstant()
                .minusSeconds(clockSkew);
            if (now.isBefore(notBefore)) {
                return ConditionsValidationResult.failed(
                    "Assertion not yet valid");
            }
        }

        // Validate NotOnOrAfter
        if (conditions.getNotOnOrAfter() != null) {
            Instant notOnOrAfter = conditions.getNotOnOrAfter().toInstant()
                .plusSeconds(clockSkew);
            if (now.isAfter(notOnOrAfter)) {
                return ConditionsValidationResult.failed(
                    "Assertion expired");
            }
        }

        // Validate Audience
        boolean audienceValid = false;
        for (AudienceRestriction restriction : 
                conditions.getAudienceRestrictions()) {
            for (Audience audience : restriction.getAudiences()) {
                if (idpConfig.getExpectedAudiences().contains(
                        audience.getAudienceURI())) {
                    audienceValid = true;
                    break;
                }
            }
        }

        if (!audienceValid) {
            return ConditionsValidationResult.failed(
                "Invalid audience restriction");
        }

        // Validate OneTimeUse condition if present
        if (conditions.getOneTimeUse() != null) {
            // Already handled by replay detection
        }

        return ConditionsValidationResult.valid();
    }

    private SubjectConfirmationResult validateSubjectConfirmation(
            Assertion assertion, HttpServletRequest request) {
        Subject subject = assertion.getSubject();

        for (SubjectConfirmation confirmation : 
                subject.getSubjectConfirmations()) {
            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(
                    confirmation.getMethod())) {
                SubjectConfirmationData data = 
                    confirmation.getSubjectConfirmationData();

                // Validate Recipient
                String expectedRecipient = getAssertionConsumerServiceURL();
                if (data.getRecipient() != null && 
                        !expectedRecipient.equals(data.getRecipient())) {
                    return SubjectConfirmationResult.failed(
                        "Invalid recipient");
                }

                // Validate NotOnOrAfter
                if (data.getNotOnOrAfter() != null) {
                    if (Instant.now().isAfter(
                            data.getNotOnOrAfter().toInstant())) {
                        return SubjectConfirmationResult.failed(
                            "Subject confirmation expired");
                    }
                }

                // Validate InResponseTo (if we track AuthnRequests)
                // This prevents unsolicited response attacks
                if (data.getInResponseTo() != null) {
                    if (!isValidPendingAuthRequest(
                            data.getInResponseTo())) {
                        return SubjectConfirmationResult.failed(
                            "Invalid InResponseTo");
                    }
                }

                return SubjectConfirmationResult.valid();
            }
        }

        return SubjectConfirmationResult.failed(
            "No valid subject confirmation");
    }

    // IdP Configuration class for multi-IdP support
    public static class IdPConfiguration {
        private final String entityId;
        private final X509Certificate signingCertificate;
        private final Credential signingCredential;
        private final Set<String> expectedAudiences;
        private final int allowedClockSkewSeconds;
        private final boolean ocspEnabled;

        // Constructor, getters, builder pattern...
        public IdPConfiguration(String entityId, X509Certificate cert,
                Set<String> audiences, int clockSkew, boolean ocsp) {
            this.entityId = entityId;
            this.signingCertificate = cert;
            this.signingCredential = new BasicX509Credential(cert);
            this.expectedAudiences = Set.copyOf(audiences);
            this.allowedClockSkewSeconds = clockSkew;
            this.ocspEnabled = ocsp;
        }

        public String getEntityId() { return entityId; }
        public X509Certificate getSigningCertificate() { return signingCertificate; }
        public Credential getSigningCredential() { return signingCredential; }
        public Set<String> getExpectedAudiences() { return expectedAudiences; }
        public int getAllowedClockSkewSeconds() { return allowedClockSkewSeconds; }
        public boolean isOCSPEnabled() { return ocspEnabled; }
    }
}
