Your registration flow is likely vulnerable to race conditions. When multiple concurrent requests attempt to register with the same email or username, the check for existing users and the insertion of new users happen at different times, creating a Time-Of-Check-To-Time-Of-Use (TOCTOU) vulnerability.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"net/http"

	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type RegisterRequest struct {
	Email    string `json:"email"`
	Username string `json:"username"`
	Password string `json:"password"`
}

var db *sql.DB

// VULNERABLE: Race condition between check and insert
func registerHandler(w http.ResponseWriter, r *http.Request) {
	var req RegisterRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Step 1: Check if user exists (TOCTOU vulnerability starts here)
	var exists bool
	err := db.QueryRow("SELECT EXISTS(SELECT 1 FROM users WHERE email = $1 OR username = $2)",
		req.Email, req.Username).Scan(&exists)
	if err != nil {
		http.Error(w, "Database error", http.StatusInternalServerError)
		return
	}

	if exists {
		http.Error(w, "User already exists", http.StatusConflict)
		return
	}

	// Gap here: Another request can pass the check above
	// before this insert completes

	hashedPassword, _ := bcrypt.GenerateFromPassword([]byte(req.Password), bcrypt.DefaultCost)

	// Step 2: Insert new user (race condition - duplicate may be created)
	_, err = db.Exec("INSERT INTO users (email, username, password_hash) VALUES ($1, $2, $3)",
		req.Email, req.Username, string(hashedPassword))
	if err != nil {
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(map[string]string{"status": "registered"})
}
```

