const ROLE_MAPPING = {
  'idp-admin': 'admin',
  'idp-user': 'user',
  'idp-editor': 'editor'
};

passport.use(new SamlStrategy({
  entryPoint: process.env.SAML_ENTRY_POINT,
  issuer: process.env.SAML_ISSUER,
  callbackUrl: process.env.SAML_CALLBACK_URL,

  // SECURE: Certificate for signature validation
  cert: process.env.IDP_CERT,

  // SECURE: Validate audience restriction
  audience: process.env.SAML_AUDIENCE,

  // SECURE: Validate InResponseTo to prevent replay attacks
  validateInResponseTo: true,
  requestIdExpirationPeriodMs: 300000, // 5 minutes

  // SECURE: Restrict signature algorithms
  signatureAlgorithm: 'sha256',
  digestAlgorithm: 'sha256',

  // SECURE: Require signed assertions
  wantAssertionsSigned: true,
  wantAuthnResponseSigned: true,

  // SECURE: Clock skew tolerance
  acceptedClockSkewMs: 60000 // 1 minute max
}, (profile, done) => {
  try {
    // SECURE: Validate required fields
    if (!profile.nameID || !profile.email) {
      return done(new Error('Missing required SAML attributes'));
    }

    // SECURE: Validate email domain
    const emailDomain = profile.email.split('@')[1];
    if (!process.env.ALLOWED_EMAIL_DOMAINS.split(',').includes(emailDomain)) {
      console.warn(`Rejected login from unauthorized domain: ${emailDomain}`);
      return done(new Error('Unauthorized email domain'));
    }

    // SECURE: Map IdP roles to application roles (never trust directly)
    const idpRole = profile.role || 'idp-user';
    const mappedRole = ROLE_MAPPING[idpRole] || 'user';

    if (!ALLOWED_ROLES.includes(mappedRole)) {
      return done(new Error('Invalid role assignment'));
    }

    const user = {
      id: crypto.randomUUID(), // Generate our own ID
      nameID: profile.nameID,
      email: profile.email.toLowerCase(),
      role: mappedRole,
      sessionIndex: profile.sessionIndex,
      authenticatedAt: new Date().toISOString()
    };

    return done(null, user);
  } catch (error) {
    console.error('SAML profile validation error:', error);
    return done(error);
  }
}));

app.post('/auth/saml/callback',
  passport.authenticate('saml', { failureRedirect: '/login' }),
  (req, res) => {
    console.info(`SSO login successful: ${req.user.email}`);
    res.redirect('/dashboard');
  }
);
```

**Key Security Controls**:
- **Signature validation enforced**: `wantAssertionsSigned` and `wantAuthnResponseSigned` ensure cryptographic verification
- **Audience restriction**: Prevents SAML response replay to different service providers
- **InResponseTo validation**: Binds responses to specific requests, preventing replay attacks
- **Role mapping**: Never trusts IdP-provided roles directly; maps to application-defined roles
- **Algorithm restrictions**: Prevents downgrade attacks to weak signature algorithms

