                return;
            }

            // Race window: Another thread can insert between check and insert
            String hashedPassword = BCrypt.hashpw(password, BCrypt.gensalt());
            String insertSql = "INSERT INTO users (email, password, username) VALUES (?, ?, ?)";
            PreparedStatement insertStmt = conn.prepareStatement(insertSql);
            insertStmt.setString(1, email);
            insertStmt.setString(2, hashedPassword);
            insertStmt.setString(3, username);
            insertStmt.executeUpdate();

            response.setStatus(201);
            response.getWriter().write("{\"message\": \"User registered\"}");
        } catch (SQLException e) {
            response.setStatus(500);
        }
    }
}
```

**Attack Payload**:
```bash
# Concurrent registration attack using curl
# Run multiple instances simultaneously
for i in {1..50}; do
  curl -X POST http://target.com/register \
    -d "email=victim@example.com&password=attacker123&username=attacker$i" &
done
wait
```

**Why This Is Dangerous**:
- Check-then-act pattern creates a race window between SELECT and INSERT
- Concurrent requests can pass the uniqueness check simultaneously
- Multiple accounts with same email can be created, bypassing business logic
- Attackers can claim emails before legitimate users
- Can bypass email verification by creating pre-verified duplicate accounts

**SECURE VERSION**:

```java
import java.sql.*;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;
import java.util.logging.Logger;

public class SecureUserRegistrationServlet extends HttpServlet {
    private static final Logger LOGGER = Logger.getLogger(SecureUserRegistrationServlet.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String email = request.getParameter("email").toLowerCase().trim();
        String password = request.getParameter("password");
        String username = request.getParameter("username");
        String clientIp = request.getRemoteAddr();

        // Input validation
        if (!isValidEmail(email) || !isValidPassword(password)) {
            response.setStatus(400);
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            conn.setAutoCommit(false);
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

            try {
                String hashedPassword = BCrypt.hashpw(password, BCrypt.gensalt(12));

                // SECURE: Use INSERT with ON CONFLICT to atomically handle duplicates
                // This eliminates the race condition entirely
                String insertSql = "INSERT INTO users (email, password, username, created_at) " +
                                   "VALUES (?, ?, ?, NOW()) " +
                                   "ON CONFLICT (email) DO NOTHING " +
                                   "RETURNING id";

                PreparedStatement insertStmt = conn.prepareStatement(insertSql);
                insertStmt.setString(1, email);
                insertStmt.setString(2, hashedPassword);
                insertStmt.setString(3, username);

                ResultSet rs = insertStmt.executeQuery();

                if (rs.next()) {
                    // Insert succeeded - new user created
                    long userId = rs.getLong("id");
                    conn.commit();

                    LOGGER.info(String.format("New user registered: id=%d, email=%s, ip=%s",
                        userId, maskEmail(email), clientIp));

                    response.setStatus(201);
                    response.getWriter().write("{\"message\": \"User registered\"}");
                } else {
                    // ON CONFLICT triggered - email already exists
                    conn.rollback();

                    LOGGER.warning(String.format("Duplicate registration attempt: email=%s, ip=%s",
                        maskEmail(email), clientIp));

                    response.setStatus(409);
                    response.getWriter().write("{\"error\": \"Email already registered\"}");
                }
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            LOGGER.severe("Registration error: " + e.getMessage());
            response.setStatus(500);
        }
    }

    private boolean isValidEmail(String email) {
        return email != null && email.matches("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$");
    }

    private boolean isValidPassword(String password) {
        return password != null && password.length() >= 12;
    }

    private String maskEmail(String email) {
        int atIndex = email.indexOf('@');
        if (atIndex > 2) {
            return email.substring(0, 2) + "***" + email.substring(atIndex);
        }
        return "***";
    }
}
```

**Key Security Controls**:
- **Atomic INSERT with ON CONFLICT**: Eliminates race condition by combining check and insert into single atomic operation
- **SERIALIZABLE transaction isolation**: Prevents concurrent transactions from interleaving
- **Database-level UNIQUE constraint**: Final defense ensuring email uniqueness regardless of application code
- **Input normalization**: Lowercase and trim email to prevent bypass via case variations

Excellent question! Race conditions in token-based flows are even more critical because they can lead to account takeover. Here's a production-ready pattern that addresses race conditions across all authentication token flows.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;
import java.util.logging.Logger;
import javax.servlet.http.*;

public class SecureTokenService {
    private static final Logger LOGGER = Logger.getLogger(SecureTokenService.class.getName());
    private static final SecureRandom SECURE_RANDOM = new SecureRandom();
    private static final int TOKEN_LENGTH = 32;
    private static final int TOKEN_EXPIRY_MINUTES = 15;

    // Rate limiting: IP -> (timestamp, count)
    private static final ConcurrentHashMap<String, RateLimitEntry> rateLimitMap = new ConcurrentHashMap<>();
    private static final int MAX_REQUESTS_PER_HOUR = 5;

    private final Connection conn;

    public SecureTokenService(Connection conn) {
        this.conn = conn;
    }

    /**
     * Initiates password reset with race-condition-safe token generation
     */
    public boolean initiatePasswordReset(String email, String clientIp) throws SQLException {
        // Rate limiting check
        if (isRateLimited(clientIp)) {
            LOGGER.warning(String.format("Rate limited password reset: ip=%s", clientIp));
            return false;
        }

        conn.setAutoCommit(false);
        conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

        try {
            // Lock the user row to prevent concurrent token generation
            String lockSql = "SELECT id, email FROM users WHERE email = ? FOR UPDATE NOWAIT";
            PreparedStatement lockStmt = conn.prepareStatement(lockSql);
            lockStmt.setString(1, email.toLowerCase().trim());

            ResultSet userRs = lockStmt.executeQuery();

            if (!userRs.next()) {
                conn.rollback();
                // Don't reveal if email exists - timing attack prevention
                simulateDelay();
                LOGGER.info(String.format("Password reset for non-existent email: %s, ip=%s", 
                    maskEmail(email), clientIp));
                return true; // Return success to prevent enumeration
            }

            long userId = userRs.getLong("id");

            // Invalidate ALL existing tokens for this user atomically
            String invalidateSql = "UPDATE password_reset_tokens SET invalidated = TRUE, " +
                                   "invalidated_at = NOW() WHERE user_id = ? AND invalidated = FALSE";
            PreparedStatement invalidateStmt = conn.prepareStatement(invalidateSql);
            invalidateStmt.setLong(1, userId);
            int invalidatedCount = invalidateStmt.executeUpdate();

            // Generate cryptographically secure token
            String token = generateSecureToken();
            String tokenHash = hashToken(token);
            Instant expiresAt = Instant.now().plus(TOKEN_EXPIRY_MINUTES, ChronoUnit.MINUTES);

            // Insert new token with atomic uniqueness check
            String insertSql = "INSERT INTO password_reset_tokens " +
                               "(user_id, token_hash, expires_at, created_ip, invalidated) " +
                               "VALUES (?, ?, ?, ?, FALSE) " +
                               "ON CONFLICT (token_hash) DO NOTHING " +
                               "RETURNING id";

            PreparedStatement insertStmt = conn.prepareStatement(insertSql);
            insertStmt.setLong(1, userId);
            insertStmt.setString(2, tokenHash);
            insertStmt.setTimestamp(3, Timestamp.from(expiresAt));
            insertStmt.setString(4, clientIp);

            ResultSet tokenRs = insertStmt.executeQuery();

            if (!tokenRs.next()) {
                // Token collision (extremely rare with 256-bit tokens)
                conn.rollback();
                LOGGER.severe("Token collision detected - potential attack");
                return false;
            }

            conn.commit();

            LOGGER.info(String.format("Password reset initiated: userId=%d, invalidated=%d, ip=%s",
                userId, invalidatedCount, clientIp));

            // Send email asynchronously (token, not hash)
            sendResetEmailAsync(email, token);

            return true;

        } catch (SQLException e) {
            conn.rollback();
            if (e.getSQLState().equals("55P03")) {
                // NOWAIT lock conflict - another request is processing
                LOGGER.warning(String.format("Concurrent password reset blocked: email=%s, ip=%s",
                    maskEmail(email), clientIp));
                return false;
            }
            throw e;
        }
    }

    /**
     * Validates and consumes password reset token atomically
     */
    public Long validateAndConsumeResetToken(String token, String newPassword, String clientIp) 
            throws SQLException {

        if (token == null || token.length() != 43) { // Base64 encoded 32 bytes
            return null;
        }

        String tokenHash = hashToken(token);

        conn.setAutoCommit(false);
        conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

        try {
            // Atomic token consumption - SELECT FOR UPDATE prevents race
            String selectSql = "SELECT t.id, t.user_id, t.expires_at, t.used, t.invalidated, " +
                               "t.created_ip, u.email " +
                               "FROM password_reset_tokens t " +
                               "JOIN users u ON t.user_id = u.id " +
                               "WHERE t.token_hash = ? FOR UPDATE NOWAIT";

            PreparedStatement selectStmt = conn.prepareStatement(selectSql);
            selectStmt.setString(1, tokenHash);
            ResultSet rs = selectStmt.executeQuery();

            if (!rs.next()) {
                conn.rollback();
                LOGGER.warning(String.format("Invalid reset token attempted: ip=%s", clientIp));
                return null;
            }

            long tokenId = rs.getLong("id");
            long userId = rs.getLong("user_id");
            Timestamp expiresAt = rs.getTimestamp("expires_at");
            boolean used = rs.getBoolean("used");
            boolean invalidated = rs.getBoolean("invalidated");
            String createdIp = rs.getString("created_ip");
            String userEmail = rs.getString("email");

            // Validate token state
            if (used) {
                conn.rollback();
                LOGGER.warning(String.format("Reused reset token: userId=%d, ip=%s", userId, clientIp));
                return null;
            }

            if (invalidated) {
                conn.rollback();
                LOGGER.warning(String.format("Invalidated reset token: userId=%d, ip=%s", userId, clientIp));
                return null;
            }

            if (expiresAt.toInstant().isBefore(Instant.now())) {
                conn.rollback();
                LOGGER.info(String.format("Expired reset token: userId=%d, ip=%s", userId, clientIp));
                return null;
            }

            // Mark token as used BEFORE updating password (fail-safe)
            String markUsedSql = "UPDATE password_reset_tokens SET used = TRUE, " +
                                 "used_at = NOW(), used_ip = ? WHERE id = ?";
            PreparedStatement markUsedStmt = conn.prepareStatement(markUsedSql);
            markUsedStmt.setString(1, clientIp);
            markUsedStmt.setLong(2, tokenId);
            markUsedStmt.executeUpdate();

            // Update password
            String hashedPassword = org.mindrot.jbcrypt.BCrypt.hashpw(newPassword, 
                org.mindrot.jbcrypt.BCrypt.gensalt(12));

            String updatePwSql = "UPDATE users SET password = ?, password_changed_at = NOW(), " +
                                 "password_version = password_version + 1 WHERE id = ?";
            PreparedStatement updatePwStmt = conn.prepareStatement(updatePwSql);
            updatePwStmt.setString(1, hashedPassword);
            updatePwStmt.setLong(2, userId);
            updatePwStmt.executeUpdate();

            // Invalidate all sessions for this user (force re-login)
            String invalidateSessionsSql = "DELETE FROM user_sessions WHERE user_id = ?";
            PreparedStatement invalidateSessionsStmt = conn.prepareStatement(invalidateSessionsSql);
            invalidateSessionsStmt.setLong(1, userId);
            int sessionsInvalidated = invalidateSessionsStmt.executeUpdate();

            conn.commit();

            LOGGER.info(String.format(
                "Password reset completed: userId=%d, sessionsInvalidated=%d, " +
                "tokenCreatedIp=%s, usedIp=%s",
                userId, sessionsInvalidated, createdIp, clientIp));

            // Send notification email
            sendPasswordChangedNotification(userEmail, clientIp);

            return userId;

        } catch (SQLException e) {
            conn.rollback();
            if (e.getSQLState().equals("55P03")) {
                LOGGER.warning(String.format("Concurrent token validation blocked: ip=%s", clientIp));
                return null;
            }
            throw e;
        }
    }

    private String generateSecureToken() {
        byte[] tokenBytes = new byte[TOKEN_LENGTH];
        SECURE_RANDOM.nextBytes(tokenBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }

    private String hashToken(String token) {
        try {
            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(token.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new RuntimeException("Hash algorithm not available", e);
        }
    }

    private boolean isRateLimited(String ip) {
        RateLimitEntry entry = rateLimitMap.compute(ip, (k, v) -> {
            long now = System.currentTimeMillis();
            if (v == null || now - v.timestamp > TimeUnit.HOURS.toMillis(1)) {
                return new RateLimitEntry(now, 1);
            }
            v.count++;
            return v;
        });
        return entry.count > MAX_REQUESTS_PER_HOUR;
    }

    private void simulateDelay() {
        try {
            Thread.sleep(100 + SECURE_RANDOM.nextInt(50));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    private String maskEmail(String email) {
        int atIndex = email.indexOf('@');
        if (atIndex > 2) {
            return email.substring(0, 2) + "***" + email.substring(atIndex);
        }
        return "***";
    }

    private void sendResetEmailAsync(String email, String token) {
        // Implementation: Queue email for async sending
    }

    private void sendPasswordChangedNotification(String email, String ip) {
        // Implementation: Notify user of password change
    }

    private static class RateLimitEntry {
        long timestamp;
        int count;
        RateLimitEntry(long timestamp, int count) {
            this.timestamp = timestamp;
            this.count = count;
        }
    }
}
```

**Defense in Depth Layers**:

1. **Database Row Locking (FOR UPDATE NOWAIT)**:
```sql
-- Prevents concurrent modifications to the same user/token
SELECT * FROM password_reset_tokens WHERE token_hash = ? FOR UPDATE NOWAIT
-- NOWAIT causes immediate failure instead of waiting, preventing timing attacks
```

2. **Atomic Token Invalidation on New Request**:
```java
// All previous tokens invalidated before new one created
// Single transaction ensures no window for race condition
String invalidateSql = "UPDATE password_reset_tokens SET invalidated = TRUE " +
                       "WHERE user_id = ? AND invalidated = FALSE";
```

3. **Token Consumption Before Password Update**:
```java
// Mark token used BEFORE changing password
// If password update fails, token is already consumed (fail-safe)
markUsedStmt.executeUpdate();  // Token consumed
updatePwStmt.executeUpdate();  // Then password changed
```

**Additional Protections**:
- **Token hashing**: Only hash stored in database; attacker with DB access cannot use tokens
- **Session invalidation**: All existing sessions terminated on password change
- **IP tracking**: Both token creation and usage IPs logged for forensics
- **Rate limiting**: Per-IP limits prevent enumeration and brute force
- **Timing attack prevention**: Consistent response time regardless of email existence
- **Password version tracking**: Enables detection of stale password usage
- **Cryptographically secure tokens**: 256-bit entropy prevents guessing
- **Short expiry**: 15-minute window limits attack surface

SAML SSO implementation requires careful attention to security. Many breaches occur due to improper validation of SAML responses, allowing attackers to forge authentication assertions.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/base64"
	"encoding/xml"
	"net/http"
	"strings"
)

type SAMLResponse struct {
	XMLName   xml.Name `xml:"Response"`
	Assertion struct {
		Subject struct {
			NameID string `xml:"NameID"`
		} `xml:"Subject"`
		Conditions struct {
			NotBefore    string `xml:"NotBefore,attr"`
			NotOnOrAfter string `xml:"NotOnOrAfter,attr"`
		} `xml:"Conditions"`
	} `xml:"Assertion"`
}

func handleSSOCallback(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: No signature validation
	samlResponse := r.FormValue("SAMLResponse")

	// Decode the response
	decoded, _ := base64.StdEncoding.DecodeString(samlResponse)

	var response SAMLResponse
	xml.Unmarshal(decoded, &response)

	// VULNERABLE: Directly trusting the NameID without verification
	userEmail := response.Assertion.Subject.NameID

	// VULNERABLE: No issuer validation
	// VULNERABLE: No audience restriction check
	// VULNERABLE: No time condition validation

	// Create session for the user
	session := createSession(userEmail)
	http.SetCookie(w, &http.Cookie{
		Name:  "session",
		Value: session,
	})

	http.Redirect(w, r, "/dashboard", http.StatusFound)
}

func createSession(email string) string {
	return base64.StdEncoding.EncodeToString([]byte(email))
}
```

**Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol">
  <saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion">
    <saml:Subject>
      <saml:NameID>admin@company.com</saml:NameID>
    </saml:Subject>
    <saml:Conditions NotBefore="2020-01-01T00:00:00Z" 
                     NotOnOrAfter="2099-12-31T23:59:59Z"/>
  </saml:Assertion>
</samlp:Response>
```

**Why This Is Dangerous**:
- No cryptographic signature validation allows forged SAML responses
- No issuer validation means any IdP can be spoofed
- No audience restriction check allows replay attacks across applications
- No time condition validation allows indefinite token reuse
- Attacker can impersonate any user including administrators

**SECURE VERSION**:

```go
package main

import (
	"crypto/x509"
	"encoding/base64"
	"encoding/pem"
	"errors"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/crewjam/saml/samlsp"
)

type SAMLConfig struct {
	IdPMetadataURL string
	IdPCertPEM     string
	SPEntityID     string
	ACSURL         string
	AllowedIssuers []string
}

func initSecureSAML(config SAMLConfig) (*samlsp.Middleware, error) {
	// Load and validate IdP certificate
	block, _ := pem.Decode([]byte(config.IdPCertPEM))
	if block == nil {
		return nil, errors.New("failed to parse IdP certificate PEM")
	}

	idpCert, err := x509.ParseCertificate(block.Bytes)
	if err != nil {
		return nil, errors.New("invalid IdP certificate")
	}

	// Verify certificate is not expired
	if time.Now().After(idpCert.NotAfter) {
		return nil, errors.New("IdP certificate has expired")
	}

	// Configure SAML middleware with strict validation
	opts := samlsp.Options{
		EntityID:          config.SPEntityID,
		URL:               mustParseURL(config.ACSURL),
		IDPMetadataURL:    mustParseURL(config.IdPMetadataURL),
		SignRequest:       true,
		AllowIDPInitiated: false, // Prevent unsolicited responses
	}

	middleware, err := samlsp.New(opts)
	if err != nil {
		return nil, err
	}

	return middleware, nil
}

func handleSecureSSOCallback(samlMiddleware *samlsp.Middleware) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// The middleware handles signature validation, time checks, etc.
		session := samlsp.SessionFromContext(r.Context())
		if session == nil {
			log.Printf("SECURITY: Invalid SAML session from IP %s", r.RemoteAddr)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Get validated user attributes
		sa := session.(samlsp.SessionWithAttributes)
		userEmail := sa.GetAttributes().Get("email")

		if userEmail == "" {
			log.Printf("SECURITY: SAML response missing email attribute")
			http.Error(w, "Invalid identity", http.StatusBadRequest)
			return
		}

		// Additional domain validation
		if !isAllowedDomain(userEmail) {
			log.Printf("SECURITY: Unauthorized domain in email: %s", userEmail)
			http.Error(w, "Unauthorized domain", http.StatusForbidden)
			return
		}

		log.Printf("AUTH: Successful SSO login for %s from %s", userEmail, r.RemoteAddr)

		// Create secure session
		createSecureSession(w, userEmail)
		http.Redirect(w, r, "/dashboard", http.StatusFound)
	}
}
```

**Key Security Controls**:
- **Cryptographic signature validation**: Uses library that verifies XML signatures against trusted IdP certificate
- **Issuer validation**: Only accepts responses from configured identity providers
- **Time condition enforcement**: Rejects expired or not-yet-valid assertions
- **Audience restriction**: Ensures token was issued for this specific application
- **Anti-replay protection**: Prevents assertion reuse attacks

OIDC/OAuth2 SSO has its own set of critical misconfigurations. The 2024 Descope authentication bypass (CVE-2024-21893) showed how improper token validation can lead to complete authentication bypass.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/coreos/go-oidc/v3/oidc"
	"github.com/golang-jwt/jwt/v5"
	"golang.org/x/oauth2"
)

// OIDCConfig holds secure OIDC configuration
type OIDCConfig struct {
	IssuerURL       string
	ClientID        string
	ClientSecret    string
	RedirectURL     string
	AllowedDomains  []string
	RequiredClaims  []string
	SessionDuration time.Duration
}

// SecureOIDCHandler manages OIDC authentication
type SecureOIDCHandler struct {
	provider    *oidc.Provider
	verifier    *oidc.IDTokenVerifier
	oauthConfig *oauth2.Config
	config      OIDCConfig
	stateStore  *StateStore
	nonceStore  *NonceStore
}

// StateStore prevents CSRF attacks with secure state management
type StateStore struct {
	states map[string]StateData
	mu     sync.RWMutex
}

type StateData struct {
	CreatedAt   time.Time
	RedirectURI string
	IPAddress   string
}

// NonceStore prevents replay attacks
type NonceStore struct {
	nonces map[string]time.Time
	mu     sync.RWMutex
}

func NewSecureOIDCHandler(config OIDCConfig) (*SecureOIDCHandler, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	// SECURITY: Fetch provider configuration securely
	provider, err := oidc.NewProvider(ctx, config.IssuerURL)
	if err != nil {
		return nil, fmt.Errorf("failed to get OIDC provider: %w", err)
	}

	// SECURITY: Configure strict token verification
	verifier := provider.Verifier(&oidc.Config{
		ClientID:             config.ClientID,
		SkipClientIDCheck:    false, // CRITICAL: Never skip
		SkipExpiryCheck:      false, // CRITICAL: Never skip
		SkipIssuerCheck:      false, // CRITICAL: Never skip
		SupportedSigningAlgs: []string{"RS256", "ES256"}, // Reject weak algorithms
	})

	oauthConfig := &oauth2.Config{
		ClientID:     config.ClientID,
		ClientSecret: config.ClientSecret,
		Endpoint:     provider.Endpoint(),
		RedirectURL:  config.RedirectURL,
		Scopes:       []string{oidc.ScopeOpenID, "email", "profile"},
	}

	return &SecureOIDCHandler{
		provider:    provider,
		verifier:    verifier,
		oauthConfig: oauthConfig,
		config:      config,
		stateStore:  &StateStore{states: make(map[string]StateData)},
		nonceStore:  &NonceStore{nonces: make(map[string]time.Time)},
	}, nil
}

// generateSecureRandom creates cryptographically secure random strings
func generateSecureRandom(length int) (string, error) {
	bytes := make([]byte, length)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return base64.RawURLEncoding.EncodeToString(bytes), nil
}

// StartAuth initiates the OIDC authentication flow
func (h *SecureOIDCHandler) StartAuth(w http.ResponseWriter, r *http.Request) {
	// SECURITY: Generate cryptographically secure state parameter
	state, err := generateSecureRandom(32)
	if err != nil {
		log.Printf("ERROR: Failed to generate state: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// SECURITY: Generate nonce for replay protection
	nonce, err := generateSecureRandom(32)
	if err != nil {
		log.Printf("ERROR: Failed to generate nonce: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// Store state with metadata for validation
	h.stateStore.mu.Lock()
	h.stateStore.states[state] = StateData{
		CreatedAt:   time.Now(),
		RedirectURI: r.URL.Query().Get("redirect"),
		IPAddress:   getClientIP(r),
	}
	h.stateStore.mu.Unlock()

	// Store nonce
	h.nonceStore.mu.Lock()
	h.nonceStore.nonces[nonce] = time.Now()
	h.nonceStore.mu.Unlock()

	// Set nonce in secure cookie for callback validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oidc_nonce",
		Value:    nonce,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		MaxAge:   300, // 5 minutes
	})

	// SECURITY: Use PKCE for additional protection
	authURL := h.oauthConfig.AuthCodeURL(
		state,
		oidc.Nonce(nonce),
		oauth2.SetAuthURLParam("prompt", "consent"),
	)

	log.Printf("AUTH: Starting OIDC flow from IP %s", getClientIP(r))
	http.Redirect(w, r, authURL, http.StatusFound)
}

// HandleCallback processes the OIDC callback with full validation
func (h *SecureOIDCHandler) HandleCallback(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()

	// SECURITY: Check for OAuth error response
	if errParam := r.URL.Query().Get("error"); errParam != "" {
		errDesc := r.URL.Query().Get("error_description")
		log.Printf("SECURITY: OAuth error: %s - %s from %s", errParam, errDesc, getClientIP(r))
		http.Error(w, "Authentication failed", http.StatusUnauthorized)
		return
	}

	// SECURITY: Validate state parameter (CSRF protection)
	state := r.URL.Query().Get("state")
	if err := h.validateState(state, r); err != nil {
		log.Printf("SECURITY: State validation failed: %v from %s", err, getClientIP(r))
		http.Error(w, "Invalid state", http.StatusBadRequest)
		return
	}

	// SECURITY: Get nonce from cookie
	nonceCookie, err := r.Cookie("oidc_nonce")
	if err != nil || nonceCookie.Value == "" {
		log.Printf("SECURITY: Missing nonce cookie from %s", getClientIP(r))
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}
	nonce := nonceCookie.Value

	// Exchange authorization code for tokens
	code := r.URL.Query().Get("code")
	token, err := h.oauthConfig.Exchange(ctx, code)
	if err != nil {
		log.Printf("SECURITY: Token exchange failed: %v from %s", err, getClientIP(r))
		http.Error(w, "Authentication failed", http.StatusUnauthorized)
		return
	}

	// SECURITY: Extract and verify ID token
	rawIDToken, ok := token.Extra("id_token").(string)
	if !ok {
		log.Printf("SECURITY: Missing ID token in response from %s", getClientIP(r))
		http.Error(w, "Invalid token response", http.StatusUnauthorized)
		return
	}

	// SECURITY: Verify ID token with all checks
	idToken, err := h.verifier.Verify(ctx, rawIDToken)
	if err != nil {
		log.Printf("SECURITY: ID token verification failed: %v from %s", err, getClientIP(r))
		http.Error(w, "Invalid token", http.StatusUnauthorized)
		return
	}

	// SECURITY: Validate nonce to prevent replay attacks
	if idToken.Nonce != nonce {
		log.Printf("SECURITY: Nonce mismatch - possible replay attack from %s", getClientIP(r))
		http.Error(w, "Invalid token", http.StatusUnauthorized)
		return
	}

	// Consume nonce (one-time use)
	h.nonceStore.mu.Lock()
	delete(h.nonceStore.nonces, nonce)
	h.nonceStore.mu.Unlock()

	// SECURITY: Extract and validate claims
	var claims struct {
		Email         string `json:"email"`
		EmailVerified bool   `json:"email_verified"`
		Sub           string `json:"sub"`
		Name          string `json:"name"`
		Aud           string `json:"aud"`
	}
	if err := idToken.Claims(&claims); err != nil {
		log.Printf("ERROR: Failed to parse claims: %v", err)
		http.Error(w, "Invalid token claims", http.StatusUnauthorized)
		return
	}

	// SECURITY: Verify email is verified
	if !claims.EmailVerified {
		log.Printf("SECURITY: Unverified email attempt: %s from %s", claims.Email, getClientIP(r))
		http.Error(w, "Email not verified", http.StatusForbidden)
		return
	}

	// SECURITY: Domain restriction
	if !h.isAllowedDomain(claims.Email) {
		log.Printf("SECURITY: Unauthorized domain: %s from %s", claims.Email, getClientIP(r))
		http.Error(w, "Unauthorized domain", http.StatusForbidden)
		return
	}

	// Clear nonce cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "oidc_nonce",
		Value:    "",
		Path:     "/",
		MaxAge:   -1,
		HttpOnly: true,
		Secure:   true,
	})

	// Create secure session
	if err := h.createSecureSession(w, claims.Email, claims.Sub); err != nil {
		log.Printf("ERROR: Failed to create session: %v", err)
		http.Error(w, "Session error", http.StatusInternalServerError)
		return
	}

	log.Printf("AUTH: Successful OIDC login for %s (sub: %s) from %s", 
		claims.Email, claims.Sub, getClientIP(r))

	http.Redirect(w, r, "/dashboard", http.StatusFound)
}

func (h *SecureOIDCHandler) validateState(state string, r *http.Request) error {
	if state == "" {
		return errors.New("missing state parameter")
	}

	h.stateStore.mu.Lock()
	defer h.stateStore.mu.Unlock()

	stateData, exists := h.stateStore.states[state]
	if !exists {
		return errors.New("unknown state")
	}

	// Clean up used state immediately (one-time use)
	delete(h.stateStore.states, state)

	// SECURITY: Check state age (prevent stale state attacks)
	if time.Since(stateData.CreatedAt) > 5*time.Minute {
		return errors.New("state expired")
	}

	return nil
}

func (h *SecureOIDCHandler) isAllowedDomain(email string) bool {
	parts := strings.Split(email, "@")
	if len(parts) != 2 {
		return false
	}
	domain := strings.ToLower(parts[1])

	for _, allowed := range h.config.AllowedDomains {
		if domain == strings.ToLower(allowed) {
			return true
		}
	}
	return false
}

func (h *SecureOIDCHandler) createSecureSession(w http.ResponseWriter, email, sub string) error {
	sessionID, err := generateSecureRandom(32)
	if err != nil {
		return err
	}

	// Store session in secure backend (Redis, database, etc.)
	// Session should be tied to user's sub claim, not email

	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    sessionID,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   int(h.config.SessionDuration.Seconds()),
	})

	return nil
}

func getClientIP(r *http.Request) string {
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		return strings.TrimSpace(parts[0])
	}
	return strings.Split(r.RemoteAddr, ":")[0]
}

func main() {
	config := OIDCConfig{
		IssuerURL:       "https://accounts.google.com",
		ClientID:        "your-client-id",
		ClientSecret:    "your-client-secret",
		RedirectURL:     "https://app.example.com/auth/callback",
		AllowedDomains:  []string{"example.com"},
		RequiredClaims:  []string{"email", "sub"},
		SessionDuration: 8 * time.Hour,
	}

	handler, err := NewSecureOIDCHandler(config)
	if err != nil {
		log.Fatalf("Failed to initialize OIDC: %v", err)
	}

	http.HandleFunc("/auth/login", handler.StartAuth)
	http.HandleFunc("/auth/callback", handler.HandleCallback)

	log.Fatal(http.ListenAndServeTLS(":443", "cert.pem", "key.pem", nil))
}
```

**Defense in Depth Layers**:

1. **State Parameter Validation (CSRF Protection)**:
```go
// Generate cryptographically secure state
state, _ := generateSecureRandom(32)
// Store with metadata and expiration
stateStore[state] = StateData{CreatedAt: time.Now(), IPAddress: clientIP}
// Validate: exists, not expired, single-use
```

2. **Nonce Validation (Replay Protection)**:
```go
// Nonce in authorization request
authURL := oauthConfig.AuthCodeURL(state, oidc.Nonce(nonce))
// Verify nonce in ID token matches
if idToken.Nonce != expectedNonce {
    return errors.New("nonce mismatch - replay attack")
}
```

3. **Strict Token Verification**:
```go
verifier := provider.Verifier(&oidc.Config{
    ClientID:             clientID,
    SkipClientIDCheck:    false, // Verify audience
    SkipExpiryCheck:      false, // Verify not expired
    SkipIssuerCheck:      false, // Verify issuer
    SupportedSigningAlgs: []string{"RS256", "ES256"}, // Strong algorithms only
})
```

**Additional Protections**:

- **Algorithm restriction**: Only accept RS256/ES256, reject HS256 (symmetric) to prevent key confusion attacks
- **Email verification check**: Ensure `email_verified` claim is true before trusting email
- **Domain allowlisting**: Restrict authentication to specific email domains
- **Sub claim binding**: Use the immutable `sub` claim for user identity, not email (which can change)
- **Token binding**: Tie tokens to specific client characteristics where possible
- **Secure cookie configuration**: HttpOnly, Secure, SameSite flags on all auth cookies
- **Comprehensive audit logging**: Log all authentication events with IP, user agent, and outcomes
- **Background cleanup**: Periodically clean expired states and nonces to prevent memory exhaustion

User registration has a subtle but critical vulnerability: race conditions. When two requests arrive simultaneously trying to register the same username, both might pass the uniqueness check before either completes insertion, creating duplicate accounts.

**VULNERABLE CODE**:

```php
<?php
class UserRegistration {
    private $pdo;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function register(string $username, string $email, string $password): array {
        // VULNERABLE: Check-then-act pattern creates race window
        $stmt = $this->pdo->prepare("SELECT COUNT(*) FROM users WHERE username = ?");
        $stmt->execute([$username]);

        if ($stmt->fetchColumn() > 0) {
            return ['success' => false, 'error' => 'Username already exists'];
        }

        // VULNERABLE: Time gap between check above and insert below
        // Another request could insert the same username here!

        $hashedPassword = password_hash($password, PASSWORD_DEFAULT);

        $insertStmt = $this->pdo->prepare(
            "INSERT INTO users (username, email, password_hash, created_at) VALUES (?, ?, ?, NOW())"
        );

        try {
            $insertStmt->execute([$username, $email, $hashedPassword]);
            return ['success' => true, 'user_id' => $this->pdo->lastInsertId()];
        } catch (PDOException $e) {
            return ['success' => false, 'error' => 'Registration failed'];
        }
    }
}
```

**Attack Payload**:
```bash
# Race condition exploit - send simultaneous requests
for i in {1..10}; do
    curl -X POST http://target.com/register \
        -d "username=victimuser&email=attacker$i@evil.com&password=pass123" &
done
wait
# Result: Multiple accounts created with same username
```

**Why This Is Dangerous**:
- Time-of-check-to-time-of-use (TOCTOU) vulnerability between SELECT and INSERT
- Concurrent requests can both pass the uniqueness check simultaneously
- Database may end up with duplicate usernames if no UNIQUE constraint exists
- Attacker can claim usernames before legitimate users complete registration
- Even with UNIQUE constraint, race creates inconsistent user experience

**SECURE VERSION**:

```php
<?php
class SecureUserRegistration {
    private $pdo;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
        $this->pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
    }

    public function register(string $username, string $email, string $password): array {
        // Input validation first
        if (!$this->validateUsername($username)) {
            return ['success' => false, 'error' => 'Invalid username format'];
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return ['success' => false, 'error' => 'Invalid email format'];
        }

        $hashedPassword = password_hash($password, PASSWORD_BCRYPT, ['cost' => 12]);

        // SECURE: Use database UNIQUE constraint as primary defense
        // Attempt INSERT directly - let database enforce uniqueness atomically
        try {
            $stmt = $this->pdo->prepare(
                "INSERT INTO users (username, email, password_hash, created_at) 
                 VALUES (LOWER(?), LOWER(?), ?, NOW())"
            );
            $stmt->execute([$username, $email, $hashedPassword]);

            return [
                'success' => true, 
                'user_id' => $this->pdo->lastInsertId()
            ];

        } catch (PDOException $e) {
            // SECURE: Handle duplicate key violation specifically
            if ($e->getCode() == '23000') { // Integrity constraint violation
                // Determine which field caused the duplicate
                if (strpos($e->getMessage(), 'username') !== false) {
                    return ['success' => false, 'error' => 'Username already exists'];
                }
                if (strpos($e->getMessage(), 'email') !== false) {
                    return ['success' => false, 'error' => 'Email already registered'];
                }
                return ['success' => false, 'error' => 'Account already exists'];
            }

            error_log("Registration error: " . $e->getMessage());
            return ['success' => false, 'error' => 'Registration failed'];
        }
    }

    private function validateUsername(string $username): bool {
        // 3-30 chars, alphanumeric and underscores only
        return preg_match('/^[a-zA-Z0-9_]{3,30}$/', $username) === 1;
    }
}

// Database schema MUST have UNIQUE constraints:
// CREATE UNIQUE INDEX idx_users_username ON users(LOWER(username));
// CREATE UNIQUE INDEX idx_users_email ON users(LOWER(email));
```

**Key Security Controls**:
- **Atomic database constraint**: UNIQUE index enforces uniqueness at database level, eliminating race window
- **INSERT-first pattern**: Attempt insert directly instead of check-then-act
- **Case-insensitive uniqueness**: LOWER() prevents 'Admin' vs 'admin' duplicates
- **Specific error handling**: Catch constraint violations and provide appropriate feedback

Great question! When you need pre-registration validation (invite codes, banned lists), you must use database transactions with proper locking to prevent race conditions while maintaining atomicity.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

class ProductionUserRegistration {
    private PDO $pdo;
    private RateLimiter $rateLimiter;
    private AuditLogger $auditLogger;

    private const MAX_REGISTRATION_ATTEMPTS = 5;
    private const LOCKOUT_DURATION = 900; // 15 minutes

    public function __construct(PDO $pdo, RateLimiter $rateLimiter, AuditLogger $auditLogger) {
        $this->pdo = $pdo;
        $this->pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
        $this->rateLimiter = $rateLimiter;
        $this->auditLogger = $auditLogger;
    }

    public function register(
        string $username, 
        string $email, 
        string $password,
        ?string $inviteCode = null,
        string $clientIp = ''
    ): RegistrationResult {

        // Layer 1: Rate limiting before any database operations
        if (!$this->rateLimiter->checkLimit($clientIp, 'registration', self::MAX_REGISTRATION_ATTEMPTS, self::LOCKOUT_DURATION)) {
            $this->auditLogger->log('registration_rate_limited', [
                'ip' => $clientIp,
                'username_attempted' => $username
            ]);
            return new RegistrationResult(false, 'Too many registration attempts. Please try again later.');
        }

        // Layer 2: Input validation (non-database checks first)
        $validationResult = $this->validateInput($username, $email, $password);
        if (!$validationResult->isValid()) {
            return new RegistrationResult(false, $validationResult->getError());
        }

        // Layer 3: Transaction with advisory lock for complex registration logic
        try {
            $this->pdo->beginTransaction();

            // SECURE: Advisory lock prevents concurrent registration attempts for same username
            // This lock is released when transaction commits/rolls back
            $lockKey = crc32('user_registration_' . strtolower($username));
            $lockStmt = $this->pdo->prepare("SELECT GET_LOCK(?, 5) as lock_acquired");
            $lockStmt->execute([$lockKey]);
            $lockResult = $lockStmt->fetch(PDO::FETCH_ASSOC);

            if ($lockResult['lock_acquired'] !== 1) {
                $this->pdo->rollBack();
                return new RegistrationResult(false, 'Registration temporarily unavailable. Please retry.');
            }

            try {
                // Layer 4: Check banned usernames (within lock)
                if ($this->isUsernameBanned($username)) {
                    $this->releaseLock($lockKey);
                    $this->pdo->rollBack();
                    $this->auditLogger->log('banned_username_attempt', [
                        'username' => $username,
                        'ip' => $clientIp
                    ]);
                    return new RegistrationResult(false, 'This username is not available');
                }

                // Layer 5: Validate and consume invite code atomically
                if ($inviteCode !== null) {
                    $inviteResult = $this->consumeInviteCode($inviteCode, $email);
                    if (!$inviteResult->isValid()) {
                        $this->releaseLock($lockKey);
                        $this->pdo->rollBack();
                        return new RegistrationResult(false, $inviteResult->getError());
                    }
                }

                // Layer 6: Create user with atomic uniqueness enforcement
                $hashedPassword = password_hash($password, PASSWORD_ARGON2ID, [
                    'memory_cost' => 65536,
                    'time_cost' => 4,
                    'threads' => 3
                ]);

                $userId = $this->createUser($username, $email, $hashedPassword, $inviteCode);

                // Layer 7: Create verification token
                $verificationToken = $this->createEmailVerificationToken($userId);

                $this->releaseLock($lockKey);
                $this->pdo->commit();

                // Layer 8: Audit successful registration
                $this->auditLogger->log('user_registered', [
                    'user_id' => $userId,
                    'username' => $username,
                    'ip' => $clientIp,
                    'invite_code_used' => $inviteCode !== null
                ]);

                return new RegistrationResult(true, 'Registration successful', [
                    'user_id' => $userId,
                    'verification_token' => $verificationToken
                ]);

            } catch (PDOException $e) {
                $this->releaseLock($lockKey);
                throw $e;
            }

        } catch (PDOException $e) {
            if ($this->pdo->inTransaction()) {
                $this->pdo->rollBack();
            }

            // Handle duplicate key violations
            if ($e->getCode() == '23000') {
                $errorField = $this->parseConstraintViolation($e->getMessage());
                $this->auditLogger->log('duplicate_registration_attempt', [
                    'field' => $errorField,
                    'ip' => $clientIp
                ]);
                return new RegistrationResult(false, "This {$errorField} is already registered");
            }

            // Log unexpected errors without exposing details
            $this->auditLogger->log('registration_error', [
                'error' => $e->getMessage(),
                'ip' => $clientIp
            ]);

            return new RegistrationResult(false, 'Registration failed. Please try again.');
        }
    }

    private function consumeInviteCode(string $code, string $email): ValidationResult {
        // SECURE: FOR UPDATE locks the row, preventing concurrent use
        $stmt = $this->pdo->prepare(
            "SELECT id, max_uses, current_uses, expires_at, allowed_domain 
             FROM invite_codes 
             WHERE code = ? AND is_active = 1
             FOR UPDATE"
        );
        $stmt->execute([$code]);
        $invite = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$invite) {
            return new ValidationResult(false, 'Invalid invite code');
        }

        if ($invite['expires_at'] && strtotime($invite['expires_at']) < time()) {
            return new ValidationResult(false, 'Invite code has expired');
        }

        if ($invite['max_uses'] !== null && $invite['current_uses'] >= $invite['max_uses']) {
            return new ValidationResult(false, 'Invite code has reached maximum uses');
        }

        // Check domain restriction
        if ($invite['allowed_domain']) {
            $emailDomain = substr($email, strpos($email, '@') + 1);
            if (strtolower($emailDomain) !== strtolower($invite['allowed_domain'])) {
                return new ValidationResult(false, 'Invite code is restricted to specific email domain');
            }
        }

        // Atomically increment usage counter
        $updateStmt = $this->pdo->prepare(
            "UPDATE invite_codes SET current_uses = current_uses + 1 WHERE id = ?"
        );
        $updateStmt->execute([$invite['id']]);

        return new ValidationResult(true);
    }

    private function isUsernameBanned(string $username): bool {
        $normalizedUsername = strtolower(preg_replace('/[^a-z0-9]/i', '', $username));

        $stmt = $this->pdo->prepare(
            "SELECT 1 FROM banned_usernames WHERE LOWER(pattern) = ? OR ? LIKE pattern LIMIT 1"
        );
        $stmt->execute([$normalizedUsername, $normalizedUsername]);

        return $stmt->fetch() !== false;
    }

    private function createUser(string $username, string $email, string $hashedPassword, ?string $inviteCode): int {
        $stmt = $this->pdo->prepare(
            "INSERT INTO users (username, email, password_hash, invite_code_used, status, created_at) 
             VALUES (LOWER(?), LOWER(?), ?, ?, 'pending_verification', NOW())"
        );
        $stmt->execute([$username, $email, $hashedPassword, $inviteCode]);

        return (int) $this->pdo->lastInsertId();
    }

    private function createEmailVerificationToken(int $userId): string {
        $token = bin2hex(random_bytes(32));
        $hashedToken = hash('sha256', $token);
        $expiresAt = date('Y-m-d H:i:s', strtotime('+24 hours'));

        $stmt = $this->pdo->prepare(
            "INSERT INTO email_verifications (user_id, token_hash, expires_at, created_at)
             VALUES (?, ?, ?, NOW())"
        );
        $stmt->execute([$userId, $hashedToken, $expiresAt]);

        return $token;
    }

    private function validateInput(string $username, string $email, string $password): ValidationResult {
        if (!preg_match('/^[a-zA-Z0-9_]{3,30}$/', $username)) {
            return new ValidationResult(false, 'Username must be 3-30 characters, alphanumeric and underscores only');
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL) || strlen($email) > 255) {
            return new ValidationResult(false, 'Invalid email address');
        }

        if (strlen($password) < 12 || strlen($password) > 128) {
            return new ValidationResult(false, 'Password must be 12-128 characters');
        }

        // Check password complexity
        if (!preg_match('/[A-Z]/', $password) || 
            !preg_match('/[a-z]/', $password) || 
            !preg_match('/[0-9]/', $password)) {
            return new ValidationResult(false, 'Password must contain uppercase, lowercase, and numbers');
        }

        return new ValidationResult(true);
    }

    private function releaseLock(int $lockKey): void {
        $this->pdo->prepare("SELECT RELEASE_LOCK(?)")->execute([$lockKey]);
    }

    private function parseConstraintViolation(string $message): string {
        if (stripos($message, 'username') !== false) return 'username';
        if (stripos($message, 'email') !== false) return 'email';
        return 'account';
    }
}

// Supporting classes
class RegistrationResult {
    private bool $success;
    private string $message;
    private array $data;

    public function __construct(bool $success, string $message, array $data = []) {
        $this->success = $success;
        $this->message = $message;
        $this->data = $data;
    }

    public function isSuccess(): bool { return $this->success; }
    public function getMessage(): string { return $this->message; }
    public function getData(): array { return $this->data; }
}

class ValidationResult {
    private bool $valid;
    private string $error;

    public function __construct(bool $valid, string $error = '') {
        $this->valid = $valid;
        $this->error = $error;
    }

    public function isValid(): bool { return $this->valid; }
    public function getError(): string { return $this->error; }
}
